@prefix cdi: <http://ddialliance.org/Specification/DDI-CDI/1.0/RDF/> .
@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/ref-var/measurement-value> ;
            sh:resultMessage "A DDI-CDI ReferenceVariable should specify cdi:takesSubstantiveValuesFrom - a substantive ReferenceValueDomain / ValueDomain (Required per CDIF DD Appendix 4)" ;
            sh:resultPath cdi:takesSubstantiveValuesFrom ;
            sh:resultSeverity sh:Warning ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape [ sh:message "A DDI-CDI ReferenceVariable should specify cdi:takesSubstantiveValuesFrom - a substantive ReferenceValueDomain / ValueDomain (Required per CDIF DD Appendix 4)" ;
                    sh:minCount 1 ;
                    sh:path cdi:takesSubstantiveValuesFrom ;
                    sh:severity sh:Warning ] ],
        [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/ref-var/measurement-value> ;
            sh:resultMessage "A DDI-CDI ReferenceVariable should have at least one cdi:name (ObjectName) (Required per CDIF DD Appendix 4)" ;
            sh:resultPath cdi:name ;
            sh:resultSeverity sh:Warning ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape [ sh:message "A DDI-CDI ReferenceVariable should have at least one cdi:name (ObjectName) (Required per CDIF DD Appendix 4)" ;
                    sh:minCount 1 ;
                    sh:path cdi:name ;
                    sh:severity sh:Warning ] ] .

